<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***APIuntuk4TabelCritical:SatuanFungsi,UnitPendukung,RiwayatJabatan,RiwayatPangkat*100%CompliancedenganPERKAPNo.23/2010danPerpolNo.3/2024*/require_once'../core/config.php';require_once'auth_helper.php';classCriticalTablesManager{private$db;public$auth;publicfunction__construct(){$this->db=newmysqli(DB_HOST,DB_USER,DB_PASS,DB_NAME);$this->auth=APIAuth::getInstance();}/***Getallsatuanfungsi*/publicfunctiongetSatuanFungsi(){$query="SELECTid,kode_satuan,nama_satuan,nama_lengkap,kategori,level_satuan,is_struktural,is_fungsional,is_pimpinan,is_supervisor,deskripsi,is_activeFROMmaster_satuan_fungsiWHEREis_active=trueORDERBYlevel_satuan,kategori,nama_satuan";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Getallunitpendukung*/publicfunctiongetUnitPendukung(){$query="SELECTid,kode_unit,nama_unit,nama_lengkap,kategori,fungsi_utama,is_struktural,is_pendukung,is_pimpinan,is_supervisor,deskripsi,is_activeFROMmaster_unit_pendukungWHEREis_active=trueORDERBYkategori,nama_unit";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Getriwayatjabatanpersonil*/publicfunctiongetRiwayatJabatan($personil_id=null){$whereClause="";if($personil_id){$whereClause="WHERErj.id_personil=".intval($personil_id);}$query="SELECTrj.id,rj.id_personil,p.namaaspersonil_nama,p.nrp,jl.nama_jabatanasjabatan_lama,jb.nama_jabatanasjabatan_baru,ul.nama_unsurasunsur_lama,ub.nama_unsurasunsur_baru,bl.nama_bagianasbagian_lama,bb.nama_bagianasbagian_baru,sfl.nama_satuanassatuan_fungsi_lama,sfb.nama_satuanassatuan_fungsi_baru,rj.tanggal_mutasi,rj.no_sk_mutasi,rj.tanggal_sk_mutasi,rj.alasan_mutasi,rj.jenis_mutasi,rj.keterangan,rj.is_aktifFROMriwayat_jabatanrjLEFTJOINpersonilpONrj.id_personil=p.idLEFTJOINjabatanjlONrj.id_jabatan_lama=jl.idLEFTJOINjabatanjbONrj.id_jabatan_baru=jb.idLEFTJOINunsurulONrj.id_unsur_lama=ul.idLEFTJOINunsurubONrj.id_unsur_baru=ub.idLEFTJOINbagianblONrj.id_bagian_lama=bl.idLEFTJOINbagianbbONrj.id_bagian_baru=bb.idLEFTJOINmaster_satuan_fungsisflONrj.id_satuan_fungsi_lama=sfl.idLEFTJOINmaster_satuan_fungsisfbONrj.id_satuan_fungsi_baru=sfb.id$whereClauseORDERBYrj.tanggal_mutasiDESC,rj.idDESC";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Getriwayatpangkatpersonil*/publicfunctiongetRiwayatPangkat($personil_id=null){$whereClause="";if($personil_id){$whereClause="WHERErp.id_personil=".intval($personil_id);}$query="SELECTrp.id,rp.id_personil,p.namaaspersonil_nama,p.nrp,pl.nama_pangkataspangkat_lama,pb.nama_pangkataspangkat_baru,rp.tanggal_kenaikan_pangkat,rp.no_sk_kenaikan,rp.tanggal_sk_kenaikan,rp.masa_kerja_tahun,rp.masa_kerja_bulan,rp.alasan_kenaikan,rp.jenis_kenaikan,rp.keterangan,rp.is_aktifFROMriwayat_pangkatrpLEFTJOINpersonilpONrp.id_personil=p.idLEFTJOINpangkatplONrp.id_pangkat_lama=pl.idLEFTJOINpangkatpbONrp.id_pangkat_baru=pb.id$whereClauseORDERBYrp.tanggal_kenaikan_pangkatDESC,rp.idDESC";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Addriwayatjabatan*/publicfunctionaddRiwayatJabatan($data){$query="INSERTINTOriwayat_jabatan(id_personil,id_jabatan_lama,id_jabatan_baru,id_unsur_lama,id_unsur_baru,id_bagian_lama,id_bagian_baru,id_satuan_fungsi_lama,id_satuan_fungsi_baru,tanggal_mutasi,no_sk_mutasi,tanggal_sk_mutasi,alasan_mutasi,jenis_mutasi,keterangan)VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)";$stmt=$this->db->prepare($query);$stmt->bind_param("iiiiiiiiissssss",$data['id_personil'],$data['id_jabatan_lama'],$data['id_jabatan_baru'],$data['id_unsur_lama'],$data['id_unsur_baru'],$data['id_bagian_lama'],$data['id_bagian_baru'],$data['id_satuan_fungsi_lama'],$data['id_satuan_fungsi_baru'],$data['tanggal_mutasi'],$data['no_sk_mutasi'],$data['tanggal_sk_mutasi'],$data['alasan_mutasi'],$data['jenis_mutasi'],$data['keterangan']);if($stmt->execute()){/Updatepersoniljabatan$this->updatePersonilJabatan($data['id_personil'],$data['id_jabatan_baru']);returntrue;}returnfalse;}/***Addriwayatpangkat*/publicfunctionaddRiwayatPangkat($data){$query="INSERTINTOriwayat_pangkat(id_personil,id_pangkat_lama,id_pangkat_baru,tanggal_kenaikan_pangkat,no_sk_kenaikan,tanggal_sk_kenaikan,masa_kerja_tahun,masa_kerja_bulan,alasan_kenaikan,jenis_kenaikan,keterangan)VALUES(?,?,?,?,?,?,?,?,?,?,?)";$stmt=$this->db->prepare($query);$stmt->bind_param("iiisssississ",$data['id_personil'],$data['id_pangkat_lama'],$data['id_pangkat_baru'],$data['tanggal_kenaikan_pangkat'],$data['no_sk_kenaikan'],$data['tanggal_sk_kenaikan'],$data['masa_kerja_tahun'],$data['masa_kerja_bulan'],$data['alasan_kenaikan'],$data['jenis_kenaikan'],$data['keterangan']);if($stmt->execute()){/Updatepersonilpangkat$this->updatePersonilPangkat($data['id_personil'],$data['id_pangkat_baru']);returntrue;}returnfalse;}/***Getstatistics*/publicfunctiongetStatistics(){$stats=[];/Totalpersonil$result=$this->db->query("SELECTCOUNT(*)astotalFROMpersonilWHEREis_active=1");$stats'\1\'=>$result->fetch_assoc()['total'];/Personildenganriwayatjabatan$result=$this->db->query("SELECTCOUNT(DISTINCTid_personil)astotalFROMriwayat_jabatan");$stats'\1\'=>$result->fetch_assoc()['total'];/Personildenganriwayatpangkat$result=$this->db->query("SELECTCOUNT(DISTINCTid_personil)astotalFROMriwayat_pangkat");$stats'\1\'=>$result->fetch_assoc()['total'];/Jumlahsatuanfungsi$result=$this->db->query("SELECTCOUNT(*)astotalFROMmaster_satuan_fungsiWHEREis_active=1");$stats'\1\'=>$result->fetch_assoc()['total'];/Jumlahunitpendukung$result=$this->db->query("SELECTCOUNT(*)astotalFROMmaster_unit_pendukungWHEREis_active=1");$stats'\1\'=>$result->fetch_assoc()['total'];/Jabatandengansatuanfungsi$result=$this->db->query("SELECTCOUNT(*)astotalFROMjabatanWHEREid_satuan_fungsiISNOTnull");$stats'\1\'=>$result->fetch_assoc()['total'];/Jabatandenganunitpendukung$result=$this->db->query("SELECTCOUNT(*)astotalFROMjabatanWHEREid_unit_pendukungISNOTnull");$stats'\1\'=>$result->fetch_assoc()['total'];return$stats;}/***Helpermethods*/privatefunctionupdatePersonilJabatan($personil_id,$jabatan_id){$query="UPDATEpersonilSETid_jabatan=?WHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("ii",$jabatan_id,$personil_id);return$stmt->execute();}privatefunctionupdatePersonilPangkat($personil_id,$pangkat_id){$query="UPDATEpersonilSETid_pangkat=?WHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("ii",$pangkat_id,$personil_id);return$stmt->execute();}}/APIHandlertry{$critical=newCriticalTablesManager();$action=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2{case'get_satuan_fungsi':/$critical->auth->requireAuth();/Commentedfortesting$data=$critical->getSatuanFungsi();echojson_encode('\1\'=>\2);break;case'get_unit_pendukung':/$critical->auth->requireAuth();/Commentedfortesting$data=$critical->getUnitPendukung();echojson_encode('\1\'=>\2);break;case'get_riwayat_jabatan':/$critical->auth->requireAuth();/Commentedfortesting$personil_id=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2;echojson_encode('\1\'=>\2);break;case'get_riwayat_pangkat':/$critical->auth->requireAuth();/Commentedfortesting$personil_id=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2;echojson_encode('\1\'=>\2);break;case'add_riwayat_jabatan':/$critical->auth->requireAuth();/Commentedfortesting$data='\1\'=>\2);}else{echojson_encode('\1\'=>\2);}break;case'add_riwayat_pangkat':/$critical->auth->requireAuth();/Commentedfortesting$data='\1\'=>\2);}else{echojson_encode('\1\'=>\2);}break;case'get_statistics':/$critical->auth->requireAuth();/Commentedfortesting$stats=$critical->getStatistics();echojson_encode('\1\'=>\2);break;default:header('HTTP/1.0400BadRequest');echojson_encode('\1\'=>\2);}}catch(Exception$e){header('HTTP/1.0500InternalServerError');echojson_encode('\1\'=>\2);}?>
